app = Flask(__name__)

AWS_REGION = os.getenv("AWS_REGION", "us-east-1")
S3_BUCKET = os.getenv("S3_BUCKET", "")
S3_PREFIX = os.getenv("S3_PREFIX", "screenshots")
S3_PUBLIC_BASE_URL = os.getenv("S3_PUBLIC_BASE_URL", "")
CHROME_BINARY = os.getenv("CHROME_BINARY", "")
CHROMEDRIVER_PATH = os.getenv("CHROMEDRIVER_PATH", "")
PAGELOAD_TIMEOUT = int(os.getenv("PAGELOAD_TIMEOUT", "30"))
SCREENSHOT_WIDTH = int(os.getenv("SCREENSHOT_WIDTH", "1280"))
SCREENSHOT_HEIGHT = int(os.getenv("SCREENSHOT_HEIGHT", "720"))
THUMB_WIDTH = int(os.getenv("THUMB_WIDTH", "400"))
THUMB_HEIGHT = int(os.getenv("THUMB_HEIGHT", "225"))
JPEG_QUALITY = int(os.getenv("JPEG_QUALITY", "85"))
DEFAULT_WAIT_SECONDS = float(os.getenv("DEFAULT_WAIT_SECONDS", "2.0"))
MAX_URL_LENGTH = int(os.getenv("MAX_URL_LENGTH", "2048"))

s3 = boto3.client("s3", region_name=AWS_REGION)

URL_RE = re.compile(
    r"^(https?://)"
    r"(([A-Za-z0-9-]+\.)+[A-Za-z]{2,63}|"
    r"localhost|"
    r"(\d{1,3}\.){3}\d{1,3})"
    r"(:\d{1,5})?"
    r"(/.*)?$",
    re.IGNORECASE,
)

def is_valid_url(url: str) -> bool:
    if not url or len(url) > MAX_URL_LENGTH:
        return False
    if not URL_RE.match(url.strip()):
        return False
    try:
        parsed = urlparse(url)
        return parsed.scheme in ("http", "https") and bool(parsed.netloc)
    except Exception:
        return False

def normalize_url(url: str) -> str:
    return url.strip()

def url_hash(url: str) -> str:
    return hashlib.sha256(url.encode("utf-8")).hexdigest()

def build_s3_key(url: str, ext: str = "jpg") -> str:
    h = url_hash(url)
    return f"{S3_PREFIX}/{h[:2]}/{h}.{ext}"

def s3_url_for_key(key: str) -> str:
    if S3_PUBLIC_BASE_URL:
        return f"{S3_PUBLIC_BASE_URL.rstrip('/')}/{key}"
    return f"https://{S3_BUCKET}.s3.{AWS_REGION}.amazonaws.com/{key}"

def get_chrome_driver():
    options = Options()
    options.add_argument("--headless=new")
    options.add_argument("--disable-gpu")
    options.add_argument("--no-sandbox")
    options.add_argument("--hide-scrollbars")
    options.add_argument("--disable-dev-shm-usage")
    options.add_argument("--window-size=%d,%d" % (SCREENSHOT_WIDTH, SCREENSHOT_HEIGHT))
    options.add_argument("--disable-software-rasterizer")
    options.add_argument("--disable-extensions")
    options.add_argument("--disable-background-networking")
    options.add_argument("--disable-sync")
    options.add_argument("--metrics-recording-only")
    options.add_argument("--mute-audio")
    options.add_argument("--no-first-run")
    options.add_argument("--safebrowsing-disable-auto-update")
    options.add_argument("--ignore-certificate-errors")
    options.add_argument("--allow-running-insecure-content")

    if CHROME_BINARY:
        options.binary_location = CHROME_BINARY

    if CHROMEDRIVER_PATH:
        service = ChromeService(executable_path=CHROMEDRIVER_PATH)
    elif USE_WDM:
        service = ChromeService(ChromeDriverManager().install())
    else:
        service = ChromeService()

    driver = webdriver.Chrome(service=service, options=options)
    driver.set_page_load_timeout(PAGELOAD_TIMEOUT)
    return driver

def render_page_to_png(url: str) -> bytes:
    driver = None
    try:
        driver = get_chrome_driver()
        driver.get(url)
        time.sleep(DEFAULT_WAIT_SECONDS)
        return driver.get_screenshot_as_png()
    except TimeoutException:
        if driver:
            try:
                return driver.get_screenshot_as_png()
            except Exception:
                pass
        raise
    finally:
        if driver:
            try:
                driver.quit()
            except Exception:
                pass

def create_thumbnail(image_bytes: bytes) -> bytes:
    image = Image.open(io.BytesIO(image_bytes)).convert("RGB")
    image.thumbnail((THUMB_WIDTH, THUMB_HEIGHT))
    background = Image.new("RGB", (THUMB_WIDTH, THUMB_HEIGHT), (255, 255, 255))
    x = (THUMB_WIDTH - image.width) // 2
    y = (THUMB_HEIGHT - image.height) // 2
    background.paste(image, (x, y))
    out = io.BytesIO()
    background.save(out, format="JPEG", quality=JPEG_QUALITY, optimize=True)
    out.seek(0)
    return out.read()

def upload_to_s3(data: bytes, key: str, content_type: str = "image/jpeg") -> str:
    extra = {
        "ContentType": content_type,
        "ACL": "public-read",
        "CacheControl": "public, max-age=31536000, immutable",
    }
    s3.put_object(Bucket=S3_BUCKET, Key=key, Body=data, **extra)
    return s3_url_for_key(key)

def s3_object_exists(key: str) -> bool:
    try:
        s3.head_object(Bucket=S3_BUCKET, Key=key)
        return True
    except ClientError as e:
        code = e.response.get("Error", {}).get("Code", "")
        if code in ("404", "NoSuchKey", "NotFound"):
            return False
        raise

def generate_screenshot(url: str, force: bool = False) -> dict:
    key = build_s3_key(url, "jpg")
    public_url = s3_url_for_key(key)

    if not force and s3_object_exists(key):
        return {
            "url": url,
            "thumbnail_url": public_url,
            "s3_key": key,
            "cached": True,
        }

    png = render_page_to_png(url)
    thumb = create_thumbnail(png)
    upload_to_s3(thumb, key, "image/jpeg")

    return {
        "url": url,
        "thumbnail_url": public_url,
        "s3_key": key,
        "cached": False,
    }

