@app.route("/thumbnail", methods=["GET"])
def thumbnail_proxy():
    if not S3_BUCKET:
        return jsonify({"error": "S3_BUCKET is not configured"}), 500

    url = normalize_url(request.args.get("url", ""))
    force = request.args.get("force", "false").lower() in ("1", "true", "yes")

    if not is_valid_url(url):
        return jsonify({"error": "Invalid URL. Must be http/https."}), 400

    try:
        result = generate_screenshot(url, force=force)
        key = result["s3_key"]
        obj = s3.get_object(Bucket=S3_BUCKET, Key=key)
        return send_file(
            io.BytesIO(obj["Body"].read()),
            mimetype="image/jpeg",
            download_name="thumbnail.jpg",
        )
    except Exception as e:
        logger.exception("Unhandled error")
        return jsonify({"error": "Internal server error", "details": str(e)}), 500

